import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Navbar from '../components/shared/Navbar';
import { bookingAPI, providerAPI } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import { format } from 'date-fns';
import toast from 'react-hot-toast';

const STATUS_COLORS = { pending: 'warning', accepted: 'accent', in_progress: 'accent', completed: 'success', rejected: 'danger', cancelled: 'danger' };
const STATUS_ICONS = { pending: '⏳', accepted: '✅', in_progress: '🔧', completed: '🎉', rejected: '❌', cancelled: '🚫' };

export default function ProviderDashboard() {
  const { user, providerProfile } = useAuth();
  const navigate = useNavigate();
  const [bookings, setBookings] = useState([]);
  const [stats, setStats] = useState([]);
  const [provider, setProvider] = useState(providerProfile);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('pending');
  const [availability, setAvailability] = useState(providerProfile?.availability?.isAvailable ?? true);

  useEffect(() => {
    if (!providerProfile && !loading) navigate('/provider-onboarding');
  }, [providerProfile]);

  const fetchBookings = () => {
    const params = {};
    if (activeTab !== 'all') params.status = activeTab;
    bookingAPI.getProviderBookings(params)
      .then(r => { setBookings(r.data.data); setStats(r.data.stats || []); })
      .catch(() => toast.error('Failed to load bookings'))
      .finally(() => setLoading(false));
  };

  useEffect(() => { fetchBookings(); }, [activeTab]);

  const updateStatus = async (bookingId, status, finalPrice) => {
    try {
      await bookingAPI.updateStatus(bookingId, { status, finalPrice });
      toast.success(`Booking ${status}`);
      fetchBookings();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Update failed');
    }
  };

  const toggleAvailability = async () => {
    const newVal = !availability;
    setAvailability(newVal);
    try {
      await providerAPI.updateAvailability({ isAvailable: newVal });
      toast.success(newVal ? 'You are now available' : 'You are now unavailable');
    } catch { setAvailability(!newVal); }
  };

  const getStatCount = (status) => stats.find(s => s._id === status)?.count || 0;

  const TABS = ['pending', 'accepted', 'in_progress', 'completed', 'all'];

  if (!providerProfile) return (
    <div><Navbar />
      <div className="page-container" style={{ paddingTop: 60, textAlign: 'center' }}>
        <h2>Complete your provider profile</h2>
        <button className="btn btn-primary" style={{ marginTop: 20 }} onClick={() => navigate('/provider-onboarding')}>Setup Profile</button>
      </div>
    </div>
  );

  return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />
      <div className="page-container" style={{ paddingTop: 32, paddingBottom: 48 }}>

        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 28, flexWrap: 'wrap', gap: 12 }}>
          <div>
            <h1 style={{ fontSize: 26, fontWeight: 800 }}>Provider Dashboard</h1>
            <p style={{ color: 'var(--text-secondary)', fontSize: 14, marginTop: 4 }}>Welcome, {user?.name} 🛠️</p>
          </div>
          <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
            <button
              className={`btn ${availability ? 'btn-success' : 'btn-danger'}`}
              onClick={toggleAvailability}>
              {availability ? '🟢 Available' : '🔴 Unavailable'}
            </button>
            <button className="btn btn-secondary" onClick={() => navigate('/provider-onboarding')}>Edit Profile</button>
          </div>
        </div>

        {/* Stats */}
        <div className="grid-4" style={{ marginBottom: 28 }}>
          {[
            { label: 'Pending', value: getStatCount('pending'), icon: '⏳', color: 'warning' },
            { label: 'Completed', value: getStatCount('completed'), icon: '✅', color: 'success' },
            { label: 'Rating', value: providerProfile?.rating?.average?.toFixed(1) || '—', icon: '⭐', color: 'accent' },
            { label: 'Total Earnings', value: `₹${(providerProfile?.totalEarnings || 0).toLocaleString()}`, icon: '💰', color: 'success' },
          ].map(s => (
            <div key={s.label} className="stat-card">
              <div className={`stat-icon`} style={{ background: `var(--${s.color}-dim)` }}>{s.icon}</div>
              <div>
                <div className="stat-value">{s.value}</div>
                <div className="stat-label">{s.label}</div>
              </div>
            </div>
          ))}
        </div>

        {/* Verification Banner */}
        {providerProfile?.verificationStatus === 'pending' && (
          <div style={{ background: 'var(--warning-dim)', border: '1px solid var(--warning)', borderRadius: 'var(--radius)', padding: '14px 18px', marginBottom: 20, display: 'flex', alignItems: 'center', gap: 10 }}>
            <span>⚠️</span>
            <p style={{ fontSize: 14, color: 'var(--warning)' }}>Your profile is pending admin verification. You can receive bookings once approved.</p>
          </div>
        )}

        {/* Tab Nav */}
        <div style={{ overflowX: 'auto', marginBottom: 20 }}>
          <div className="tab-nav" style={{ width: 'max-content' }}>
            {TABS.map(t => (
              <button key={t} className={`tab-btn ${activeTab === t ? 'active' : ''}`} onClick={() => setActiveTab(t)}>
                {t === 'all' ? 'All' : `${STATUS_ICONS[t]} ${t.replace('_', ' ')} ${getStatCount(t) > 0 ? `(${getStatCount(t)})` : ''}`}
              </button>
            ))}
          </div>
        </div>

        {loading ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
            {[...Array(4)].map((_, i) => <div key={i} className="skeleton" style={{ height: 130 }} />)}
          </div>
        ) : bookings.length === 0 ? (
          <div className="empty-state card">
            <div className="empty-state-icon">📋</div>
            <h3>No {activeTab !== 'all' ? activeTab : ''} bookings</h3>
            <p>Bookings from customers will appear here</p>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
            {bookings.map(b => (
              <div key={b._id} className="card">
                <div style={{ display: 'flex', gap: 14, flexWrap: 'wrap' }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', flexWrap: 'wrap', gap: 8, marginBottom: 8 }}>
                      <div>
                        <div style={{ fontWeight: 700 }}>{b.user?.name}</div>
                        <div style={{ fontSize: 13, color: 'var(--text-secondary)' }}>{b.user?.phone}</div>
                      </div>
                      <span className={`badge badge-${STATUS_COLORS[b.status]}`}>
                        {STATUS_ICONS[b.status]} {b.status.replace('_', ' ')}
                      </span>
                    </div>

                    <div style={{ display: 'flex', gap: 12, fontSize: 13, color: 'var(--text-secondary)', flexWrap: 'wrap', marginBottom: 12 }}>
                      <span>🔧 {b.skillRequired}</span>
                      <span>📅 {format(new Date(b.scheduledDate), 'EEE, d MMM')} at {b.scheduledTime}</span>
                      <span>📍 {b.address?.text?.substring(0, 40)}...</span>
                    </div>

                    {b.description && (
                      <p style={{ fontSize: 13, color: 'var(--text-muted)', background: 'var(--bg-secondary)', padding: '8px 12px', borderRadius: 8, marginBottom: 12 }}>
                        "{b.description.substring(0, 100)}"
                      </p>
                    )}

                    {/* Action Buttons */}
                    <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                      {b.status === 'pending' && (
                        <>
                          <button className="btn btn-success btn-sm" onClick={() => updateStatus(b._id, 'accepted')}>✅ Accept</button>
                          <button className="btn btn-danger btn-sm" onClick={() => updateStatus(b._id, 'rejected')}>❌ Reject</button>
                        </>
                      )}
                      {b.status === 'accepted' && (
                        <button className="btn btn-primary btn-sm" onClick={() => updateStatus(b._id, 'in_progress')}>🔧 Start Job</button>
                      )}
                      {b.status === 'in_progress' && (
                        <button className="btn btn-success btn-sm" onClick={() => {
                          const price = prompt('Enter final price (₹):');
                          if (price) updateStatus(b._id, 'completed', Number(price));
                        }}>🎉 Mark Complete</button>
                      )}
                      <button className="btn btn-ghost btn-sm" onClick={() => navigate(`/chat/${b.user?._id}`)}>💬 Chat</button>
                      <button className="btn btn-ghost btn-sm" onClick={() => navigate(`/bookings/${b._id}`)}>View Details</button>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
